THOUGHT: The crash occurs because improveShuffleKindFromMask calls ShuffleVectorInst::isReverseMask/isSingleSourceMask on a mask that contains poison (-1), but isSingleSourceMaskImpl asserts that elements are in [0, NumOpElts*2). To fix, I will update BasicTTIImpl::improveShuffleKindFromMask to detect poison elements in the mask and avoid calling these helpers when poison is present, falling back to default behavior. This prevents out-of-bounds assertions while preserving correctness.

```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/include/llvm/CodeGen/BasicTTIImpl.h
@@
   TargetTransformInfo::ShuffleKind improveShuffleKindFromMask(
       TargetTransformInfo::ShuffleKind SK, ArrayRef<int> Mask, VectorType *VTy,
       int &SrcOpIdx, VectorType *&SrcVTy) const {
+    // If the mask contains poison elements (-1), some IR helpers like
+    // isSingleSourceMask/isReverseMask assert on out-of-bounds indices.
+    // In that case, conservatively avoid attempting to refine the kind
+    // based on those predicates and just return the input kind.
+    auto HasPoison = llvm::any_of(Mask, [](int M) { return M == llvm::ShuffleVectorInst::PoisonMaskElem; });
+    if (HasPoison)
+      return SK;
@@
     if (ShuffleVectorInst::isReverseMask(Mask, VTy->getElementCount())) {
       SrcOpIdx = 0;
       SrcVTy = VTy;
       return TargetTransformInfo::SK_Reverse;
     }
*** End Patch
EOF
```

